def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"{campo}: vacío tras strip")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"{campo}: no es entero ({valor!r})")

for v in [" 21 ", "", "abc", "  "]:
    print(repr(v), "→", safe_int("edad", v))

from decimal import Decimal, InvalidOperation, ROUND_HALF_EVEN

def pipeline_edad_monto(edad_txt: str, monto_txt: str) -> dict:
    raw = {"edad": edad_txt, "monto": monto_txt}
    clean = {}
    errors = []
    t = edad_txt.strip()
    if t == "":
        errors.append("edad: vacío")
    else:
        try:
            clean["edad"] = int(t)
        except ValueError:
            errors.append(f"edad: no int ({edad_txt!r})")
    mt = monto_txt.strip()
    if mt == "":
        errors.append("monto: vacío")
    else:
        try:
            clean["monto"] = Decimal(mt).quantize(Decimal("0.01"), rounding=ROUND_HALF_EVEN)
        except (InvalidOperation, ValueError):
            errors.append(f"monto: no Decimal ({monto_txt!r})")
    return {"raw": raw, "clean": clean, "errors": errors}

for a, b in [("34", "150.50"), ("xx", "99.00"), ("21", "abc")]:
    print(pipeline_edad_monto(a, b))

